1	import { useState } from "react";
2	import { Link } from "react-router-dom";
3	import { useMarkets } from "@/lib/query/hooks";
4	import { StatusBadge } from "@/components/ui/StatusBadge";
5	import { LoadingPage, ErrorMessage } from "@/components/ui/Spinner";
6	import { formatCurrency, timeUntil } from "@/lib/utils/format";
7	import type { MarketSortField } from "@/lib/api/types";
8	
9	const STATUSES = ["", "active", "resolved", "closed", "draft"] as const;
10	type StatusFilter = (typeof STATUSES)[number];
11	
12	const SORT_OPTIONS: Array<{ value: MarketSortField | ""; label: string }> = [
13	  { value: "", label: "Default order" },
14	  { value: "volume", label: "Volume (high to low)" },
15	  { value: "liquidity", label: "Liquidity (high to low)" },
16	  { value: "created", label: "Newest first" },
17	];
18	
19	export default function MarketList() {
20	  const [statusFilter, setStatusFilter] = useState<StatusFilter>("");
21	  const [sortField, setSortField] = useState<MarketSortField | "">("");
22	  const [searchQuery, setSearchQuery] = useState("");
23	
24	  const marketFilters = {
25	    ...(statusFilter ? { status: statusFilter } : {}),
26	    ...(sortField ? { sort: sortField } : {}),
27	    ...(searchQuery.trim() ? { q: searchQuery.trim() } : {}),
28	  };
29	  const hasFilters = Object.keys(marketFilters).length > 0;
30	  const { data, isLoading, error } = useMarkets(hasFilters ? marketFilters : undefined);
31	
32	  return (
33	    <div>
34	      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "var(--space-lg)" }}>
35	        <h1 style={{ fontSize: "1.5rem", fontWeight: 600 }}>Markets</h1>
36	        <div style={{ display: "flex", gap: "var(--space-sm)", alignItems: "center" }}>
37	          <input
38	            type="text"
39	            placeholder="Search markets..."
40	            value={searchQuery}
41	            onChange={(e) => setSearchQuery(e.target.value)}
42	            style={{
43	              padding: "6px 12px",
44	              borderRadius: "var(--radius-sm)",
45	              border: "1px solid var(--color-border)",
46	              background: "var(--color-bg-surface)",
47	              color: "var(--color-text)",
48	              fontSize: "0.875rem",
49	              width: "180px",
50	            }}
51	          />
52	          <select
53	            aria-label="Sort by"
54	            value={sortField}
55	            onChange={(e) => setSortField(e.target.value as MarketSortField | "")}
56	            style={{
57	              padding: "6px 12px",
58	              borderRadius: "var(--radius-sm)",
59	              border: "1px solid var(--color-border)",
60	              background: "var(--color-bg-surface)",
61	              color: "var(--color-text)",
62	              fontSize: "0.875rem",
63	            }}
64	          >
65	            {SORT_OPTIONS.map((opt) => (
66	              <option key={opt.value} value={opt.value}>{opt.label}</option>
67	            ))}
68	          </select>
69	          <select
70	            aria-label="Filter by status"
71	            value={statusFilter}
72	            onChange={(e) => setStatusFilter(e.target.value as StatusFilter)}
73	            style={{
74	              padding: "6px 12px",
75	              borderRadius: "var(--radius-sm)",
76	              border: "1px solid var(--color-border)",
77	              background: "var(--color-bg-surface)",
78	              color: "var(--color-text)",
79	              fontSize: "0.875rem",
80	            }}
81	          >
82	            {STATUSES.map((s) => (
83	              <option key={s} value={s}>{s || "All statuses"}</option>
84	            ))}
85	          </select>
86	          <Link
87	            to="/markets/new"
88	            style={{
89	              padding: "6px 14px",
90	              borderRadius: "var(--radius-sm)",
91	              background: "var(--color-primary)",
92	              color: "#fff",
93	              fontSize: "0.875rem",
94	              fontWeight: 600,
95	              textDecoration: "none",
96	            }}
97	          >
98	            + New Market
99	          </Link>
100	        </div>
101	      </div>
102	
103	      {isLoading && <LoadingPage />}
104	      {error && <ErrorMessage message={error instanceof Error ? error.message : "Failed to load markets"} />}
105	
106	      {data && data.markets.length > 0 && (
107	        <div style={{ display: "flex", gap: "var(--space-lg)", fontSize: "0.8rem", color: "var(--color-text-muted)", marginBottom: "var(--space-md)" }}>
108	          <span>{data.markets.length} market{data.markets.length !== 1 ? "s" : ""}</span>
109	          <span>Total Volume: {formatCurrency(data.markets.reduce((s, m) => s + m.volume, 0))}</span>
110	          <span>Total Liquidity: {formatCurrency(data.markets.reduce((s, m) => s + m.liquidity, 0))}</span>
111	        </div>
112	      )}
113	
114	      {data && (
115	        <div style={{ display: "grid", gap: "var(--space-md)", gridTemplateColumns: "repeat(auto-fill, minmax(360px, 1fr))" }}>
116	          {data.markets.map((m) => (
117	            <Link
118	              key={m.id}
119	              to={`/markets/${m.id}`}
120	              style={{
121	                display: "block",
122	                padding: "var(--space-md)",
123	                borderRadius: "var(--radius-md)",
124	                background: "var(--color-bg-surface)",
125	                border: "1px solid var(--color-border)",
126	                textDecoration: "none",
127	                color: "inherit",
128	                transition: "border-color 0.15s",
129	              }}
130	              onMouseEnter={(e) => (e.currentTarget.style.borderColor = "var(--color-primary)")}
131	              onMouseLeave={(e) => (e.currentTarget.style.borderColor = "var(--color-border)")}
132	            >
133	              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "start", marginBottom: "var(--space-sm)" }}>
134	                <span style={{ fontWeight: 500, fontSize: "0.95rem" }}>{m.title}</span>
135	                <StatusBadge status={m.status} />
136	              </div>
137	              <div style={{ display: "flex", gap: "var(--space-lg)", fontSize: "0.8rem", color: "var(--color-text-muted)", marginBottom: "var(--space-sm)" }}>
138	                <span>Vol {formatCurrency(m.volume)}</span>
139	                <span>Liq {formatCurrency(m.liquidity)}</span>
140	                <span>{timeUntil(m.expires_at)}</span>
141	              </div>
142	            </Link>
143	          ))}
144	        </div>
145	      )}
146	
147	      {data && data.markets.length === 0 && (
148	        <div style={{ textAlign: "center", padding: "var(--space-xl)", color: "var(--color-text-muted)" }}>
149	          No markets found.
150	        </div>
151	      )}
152	    </div>
153	  );
154	}
