1	import { useState } from "react";
2	import { useParams } from "react-router-dom";
3	import { useMarket, useMarketEvents, useAccountRisk, useMarketPriceSubscription } from "@/lib/query/hooks";
4	import { useSession } from "@/features/session/context";
5	import { StatusBadge } from "@/components/ui/StatusBadge";
6	import { ProbabilityBar } from "@/components/ui/ProbabilityBar";
7	import { LoadingPage, ErrorMessage } from "@/components/ui/Spinner";
8	import { formatCurrency, timeUntil, truncateHash, formatRelativeTime } from "@/lib/utils/format";
9	import { AssumptionProvider } from "@/features/assumptions/AssumptionContext";
10	import { AssumptionPanel } from "@/features/assumptions/AssumptionPanel";
11	import { BayesNetGraph } from "@/features/graph/BayesNetGraph";
12	import { JunctionTreePanel } from "@/features/graph/JunctionTreePanel";
13	import { DiscussionThread } from "@/features/market/DiscussionThread";
14	import { ResolveMarketPanel } from "@/features/market/ResolveMarketPanel";
15	import { EventTradePanel } from "@/features/trading/EventTradePanel";
16	import { MarketAnalytics, PnLSummary } from "@/features/analytics";
17	import type { MarketEvent } from "@/lib/api/types";
18	
19	export default function MarketDetail() {
20	  const { marketId } = useParams<{ marketId: string }>();
21	  const { session, isConfigured } = useSession();
22	  const { data, isLoading, error } = useMarket(marketId!);
23	  const events = useMarketEvents(marketId!);
24	  const accountRisk = useAccountRisk(session.accountId);
25	  const isActiveMarket = data?.market.status === "active";
26	
27	  useMarketPriceSubscription(marketId ?? "", {
28	    enabled: Boolean(marketId) && !isLoading && !error && isActiveMarket,
29	  });
30	
31	  if (isLoading) return <LoadingPage />;
32	  if (error) return <ErrorMessage message={error instanceof Error ? error.message : "Market not found"} />;
33	  if (!data) return null;
34	
35	  const m = data.market;
36	
37	  return (
38	    <div style={{ display: "grid", gap: "var(--space-lg)" }}>
39	      <div>
40	        <div style={{ display: "flex", gap: "var(--space-md)", alignItems: "center", marginBottom: "var(--space-sm)" }}>
41	          <h1 style={{ fontSize: "1.5rem", fontWeight: 600 }}>{m.title}</h1>
42	          <StatusBadge status={m.status} />
43	        </div>
44	        <p style={{ color: "var(--color-text-muted)", marginBottom: "var(--space-md)" }}>{m.description}</p>
45	        <div style={{ display: "flex", gap: "var(--space-lg)", fontSize: "0.85rem", color: "var(--color-text-muted)" }}>
46	          <span>Volume: {formatCurrency(m.volume)}</span>
47	          <span>Liquidity: {formatCurrency(m.liquidity)}</span>
48	          <span>Expires: {timeUntil(m.expires_at)}</span>
49	        </div>
50	      </div>
51	
52	      <ProbabilityBar outcomes={m.outcomes} marginals={m.marginals} />
53	
54	      <MarketAnalytics marketId={m.id} />
55	
56	      <PositionCard marketId={m.id} accountRisk={accountRisk.data} isConfigured={isConfigured} />
57	
58	      <PnLSummary marketId={m.id} accountId={session.accountId} />
59	
60	      <ResolveMarketPanel market={m} />
61	
62	      {m.status === "active" && (
63	        <AssumptionProvider>
64	          <AssumptionPanel market={m} />
65	        </AssumptionProvider>
66	      )}
67	
68	      <EventTradePanel market={m} />
69	
70	      <DiscussionThread market={m} />
71	
72	      <BayesNetGraph focusMarketId={m.id} />
73	
74	      {/* Event Journal */}
75	      <div>
76	        <h2 style={{ fontSize: "1.1rem", fontWeight: 600, marginBottom: "var(--space-sm)" }}>Event Journal</h2>
77	        {events.isLoading && <LoadingPage />}
78	        {events.data && events.data.events.length === 0 && (
79	          <span style={{ color: "var(--color-text-muted)", fontSize: "0.85rem" }}>No events yet.</span>
80	        )}
