80	export function normalizeMarketListFilters(
81	  filters?: MarketListFilterInput,
82	): NormalizedMarketListFilters {
83	  const status = typeof filters === "string"
84	    ? filters
85	    : filters?.status;
86	  const includeResolved = (
87	    typeof filters !== "string"
88	    && filters?.includeResolved === true
89	  ) || status === "resolved";
90	  const sort = typeof filters !== "string" ? filters?.sort : undefined;
91	  const q = typeof filters !== "string" ? filters?.q?.trim() || undefined : undefined;
92	
93	  return {
94	    ...(status ? { status } : {}),
95	    ...(includeResolved ? { includeResolved: true } : {}),
96	    ...(sort ? { sort } : {}),
97	    ...(q ? { q } : {}),
98	  };
99	}
100	
101	function serializeMarketListFilters(filters?: MarketListFilterInput): string {
102	  const normalizedFilters = normalizeMarketListFilters(filters);
103	  const params = new URLSearchParams();
104	
105	  if (normalizedFilters.status) {
106	    params.set("status", normalizedFilters.status);
107	  }
108	
109	  if (normalizedFilters.includeResolved) {
110	    params.set("include_resolved", "true");
111	  }
112	
113	  if (normalizedFilters.sort) {
114	    params.set("sort", normalizedFilters.sort);
115	  }
116	
117	  if (normalizedFilters.q) {
118	    params.set("q", normalizedFilters.q);
119	  }
120	
121	  const queryString = params.toString();
122	  return queryString ? `?${queryString}` : "";
123	}
