62	function formatTradeError(error: unknown): string {
63	  if (!(error instanceof BayesApiError) || error.code !== "position_limit_exceeded") {
64	    return error instanceof Error ? error.message : "Trade failed";
65	  }
66	
67	  const { requestedSize, currentNetSize, resultingNetSize, maxPositionSize } = readPositionLimitDetails(error);
68	  if (
69	    requestedSize == null
70	    || currentNetSize == null
71	    || resultingNetSize == null
72	    || maxPositionSize == null
73	  ) {
74	    return "Position limit exceeded. Trade would exceed the max position size for this outcome.";
75	  }
76	
77	  return `Position limit exceeded. Requested size ${formatPositionSize(requestedSize)} would move net size from ${formatPositionSize(currentNetSize)} to ${formatPositionSize(resultingNetSize)}; max position size is ${formatPositionSize(maxPositionSize)}.`;
