105	function resolveMarketListResponse(filters?: MarketListFilterInput): MarketListResponse {
106	  const status = typeof filters === "string"
107	    ? filters
108	    : filters?.status;
109	
110	  if (!status) {
111	    return defaultMarketsResponse;
112	  }
113	
114	  if (status === "active") {
115	    return activeMarketsResponse;
116	  }
117	
118	  if (status === "resolved") {
119	    return resolvedMarketsResponse;
120	  }
121	
122	  throw new Error(`Unexpected market list filters: ${JSON.stringify(filters)}`);
123	}
